                if (result && result.success) {
                    showToast('success', '推流已启动: ' + deviceId);
                    addLog('success', result.message || '推流启动成功');
                    document.getElementById('btnStreamStop').disabled = false;
                    document.getElementById('streamStatusInfo').textContent = '状态: 推流中 (Stream: ' + (result.stream_id || deviceId) + ')';
