function speedTestRun() {
    if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', '请先在「设备管理」中连接设备'); return; }
    var deviceIp = window.connectedDevice.ip;
    var device = window.connectedDevice;
