    btn.disabled = true;
    btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> 测试中...';
    document.getElementById('speedProgress').style.display = 'block';
    document.getElementById('speedResultArea').innerHTML = '';
    addLog('info', '速度测试开始: ' + deviceIp);
    apiPost('/api/v1/advanced/speed/run', {
        device_ip: deviceIp,
        username: (device && device.username) || 'admin',
        password: (device && device.password) || '',
        port: (device && device.port) || 80
    }).then(function(resp) {
        btn.disabled = false;
        btn.innerHTML = '▶ 开始测试';
        document.getElementById('speedProgress').style.display = 'none';
        if (resp && resp.success) {
            showToast('success', '速度测试完成');
            addLog('success', '速度测试完成: ' + (resp.message || ''));
            renderSpeedResults(resp.results || {});
        } else {
            showToast('error', resp ? resp.message : '测试失败');
            addLog('error', '速度测试失败: ' + (resp ? resp.message : '未知'));
        }
    }).catch(function(e) {
        btn.disabled = false;
        btn.innerHTML = '▶ 开始测试';
        document.getElementById('speedProgress').style.display = 'none';
        showToast('error', '测试异常: ' + e.message);
    });
    // Progress bar: real status (no hardcoded speed labels)
    var speedProgText = document.getElementById('speedProgressText');
    var speedProgBar = document.getElementById('speedProgressBar');
    if (speedProgText) speedProgText.textContent = '测试中... 等待设备响应';
    if (speedProgBar) speedProgBar.style.width = '30%';
    // REMOVED simulateProgress (was hardcoded: '速度档位 1', '50', '100')
    // Speed results now display actual values returned from backend
}
function renderSpeedResults(results) {
    var area = document.getElementById('speedResultArea');
    if (!results || Object.keys(results).length === 0) {
        area.innerHTML = '<div class="advanced-status-panel"><p style="color:#6e7681">暂无结果</p></div>';
        return;
    }
    var html = '<div class="advanced-status-panel"><h4>速度测试结果</h4>';
    // Speed mapping table
    var speedMap = results.speed_map || results.speed_mapping || {};
    var mapKeys = Object.keys(speedMap);
    if (mapKeys.length > 0) {
        html += '<table class="result-table" style="margin:12px 0"><thead><tr><th>速度档位</th><th>实际速率 (°/s)</th></tr></thead><tbody>';
        mapKeys.forEach(function(k) {
            html += '<tr><td>' + k + '</td><td>' + speedMap[k] + '</td></tr>';
        });
        html += '</tbody></table>';
    }
    html += '<div class="status-row"><span class="status-label">拟合曲线 R²</span><span class="status-value">' + (results.r_squared || results.r2 || '--') + '</span></div>';
    html += '<div class="status-row"><span class="status-label">精度</span><span class="status-value">' + (results.accuracy || '--') + '</span></div>';
    html += '<div class="status-row"><span class="status-label">通过</span><span class="status-value">' + (results.passed ? '<span class="badge yes">✅</span>' : '<span class="badge no">❌</span>') + '</span></div>';
    html += '</div>';
    area.innerHTML = html;
}
// ================================================================
//  Progress Simulation
// ================================================================
function simulateProgress(textId, barId, totalSteps, labels) {
    var current = 0;
    var interval = setInterval(function() {
        current++;
        if (current > totalSteps) { clearInterval(interval); return; }
        var pct = Math.round((current / totalSteps) * 100);
        var textEl = document.getElementById(textId);
        var barEl = document.getElementById(barId);
        if (textEl) textEl.textContent = labels ? labels[current-1] : '处理中... ' + current + '/' + totalSteps;
        if (barEl) barEl.style.width = pct + '%';
    }, 2000);
}
function simulateDirections() {
    var dirs = ['P+ 移动中...', 'P- 移动中...', 'T+ 移动中...', 'T- 移动中...'];
    var i = 0;
    var interval = setInterval(function() {
        var el = document.getElementById('limitDirection');
        if (!el) { clearInterval(interval); return; }
        if (i >= dirs.length) { clearInterval(interval); el.textContent = '测试完成 ✓'; el.style.color = '#3fb950'; return; }
        el.textContent = '当前方向: ' + dirs[i];
        i++;
    }, 3000);
}
