function onConnectDeviceChange() {
    var ip = document.getElementById('advConnectDevice').value;
    var noDevice = document.getElementById('connectNoDevice');
    var controlArea = document.getElementById('connectControlArea');
    var statusSpan = document.getElementById('connectDeviceStatus');
    if (ip) {
        var device = allDevices.find(function(d) { return d.ip === ip; });
        noDevice.style.display = 'none';
        controlArea.style.display = 'block';
        statusSpan.textContent = device ? ('已连接: ' + ip) : ip;
    } else {
        noDevice.style.display = 'block';
        controlArea.style.display = 'none';
        statusSpan.textContent = '';
    }
}
