        _sock = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
        _sock.settimeout(5)
        _result = _sock.connect_ex((target_ip, 80))
        _sock.close()
        if _result != 0:
            # 设备在 SADP 发现列表中 → 跨网段，建议修改 IP
