# -*- coding: utf-8 -*-
"""主控台全面诊断测试"""
import asyncio
import sys
if sys.platform == "win32":
    sys.stdout.reconfigure(encoding="utf-8")

try:
    from playwright.async_api import async_playwright
except ImportError:
    sys.exit(1)

BASE_URL = "http://localhost:10280"
DIR = "tests/screenshots"

async def test():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=False)
        page = await browser.new_page(viewport={"width": 1400, "height": 900})

        # 监听网络请求
        page.on("response", lambda resp: print(f"  [{resp.status}] {resp.url}") if "ptz" in resp.url or "position" in resp.url else None)

        print("\n=== 诊断测试 ===")

        # 1. 打开页面
        print("\n1. 打开页面")
        await page.goto(f"{BASE_URL}/")
        await page.wait_for_timeout(2000)

        # 2. 点击设备管理 → 连接
        print("\n2. 连接设备")
        await page.click('button[data-page="devices"]')
        await page.wait_for_timeout(500)
        connect_btn = page.locator('#deviceTable button:has-text("连接")').first
        await connect_btn.click()
        await page.wait_for_timeout(3000)

        # 检查 connectedDevice
        cd = await page.evaluate("window.connectedDevice")
        print(f"  connectedDevice: {cd}")

        # 3. 回到主控台
        await page.click('button[data-page="console"]')
        await page.wait_for_timeout(1000)

        # 4. 点击获取位置
        print("\n3. 获取位置")
        await page.click('button:has-text("获取位置")')
        await page.wait_for_timeout(2000)

        pos_text = await page.locator('#ptzPosition').text_content()
        print(f"  位置显示: {pos_text}")

        # 检查 API 响应
        api_result = await page.evaluate("""async () => {
            try {
                const resp = await fetch('/api/v1/ptz/192.168.5.72/position');
                return await resp.json();
            } catch(e) { return {error: e.message}; }
        }""")
        print(f"  API 原始响应: {api_result}")

        await page.screenshot(path=f"{DIR}/diag_01_position.png")

        # 5. OSD 测试
        print("\n4. OSD 测试")
        # 检查 OSD XML 结构
        osd_result = await page.evaluate("""async () => {
            try {
                const resp = await fetch('/api/v1/ptz/192.168.5.72/osd/toggle?enabled=true', {method: 'POST'});
                return await resp.json();
            } catch(e) { return {error: e.message}; }
        }""")
        print(f"  OSD 开启: {osd_result}")

        # 6. 预置点
        print("\n5. 预置点列表")
        presets_result = await page.evaluate("""async () => {
            try {
                const resp = await fetch('/api/v1/ptz/192.168.5.72/presets');
                return await resp.json();
            } catch(e) { return {error: e.message}; }
        }""")
        print(f"  预置点: {presets_result}")

        # 7. 画面调整
        print("\n6. 画面调整测试")
        # 检查画面调整 API
        image_result = await page.evaluate("""async () => {
            try {
                const resp = await fetch('/api/v1/ptz/192.168.5.72/image/settings');
                return await resp.json();
            } catch(e) { return {error: e.message}; }
        }""")
        print(f"  画面设置: {image_result}")

        await browser.close()

if __name__ == "__main__":
    asyncio.run(test())

